[AttributeUsage(AttributeTargets.Class | AttributeTargets.Method)]
public class BypassCompanyRequiredAttribute : Attribute;

// In IAuthorizationHandler:
var endpoint = httpContext.GetEndpoint();
if (endpoint?.Metadata.GetMetadata<BypassCompanyRequiredAttribute>() is not null) { context.Succeed(requirement); return; }
var companyId = httpContext.User.FindFirst("companyId")?.Value;
if (!string.IsNullOrEmpty(companyId)) context.Succeed(requirement);
